INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '81735dff-c27a-4c3f-bfda-f63be23c526b',
  '00000000-0000-0000-0000-000000000001',
  $escape$Elasticsearch — Search Engine First, Not a Database Replacement$escape$,
  $escape$Elasticsearch is built on an inverted index, not a B-tree or LSM-tree. That architectural choice defines exactly where it fits in your stack — and where it doesn't.

It wins at full-text search with BM25 relevance scoring, near-real-time log analytics via `date_histogram` aggregations, faceted search combining `bool` filters with `terms` aggs, and vector/semantic search through `knn` queries on `dense_vector` fields. It loses hard at OLTP: there are no ACID transactions, writes aren't searchable until after a refresh cycle (default 1s), and reads are eventually consistent — a coordinating node may return a stale shard.

Relational joins are absent by design. `nested` objects and `parent-child` relationships exist but carry serious query-time costs at scale. For pure columnar analytics, ClickHouse will outperform Elasticsearch on throughput by orders of magnitude.

The right mental model: Elasticsearch is a **search layer**, not a source of truth. Pair it with PostgreSQL for authoritative state and authoritative writes. Sync to Elasticsearch via CDC or a queue for the search and aggregation surface. Pick it when your query pattern is search-first — relevance, ranking, or log grep-and-aggregate.$escape$,
  $escape$from elasticsearch import Elasticsearch

es = Elasticsearch("http://localhost:9200")

resp = es.search(
    index="logs-*",
    query={
        "bool": {
            "must": [{"match": {"message": "OutOfMemoryError"}}],
            "filter": [
                {"term": {"level": "ERROR"}},
                {"range": {"@timestamp": {"gte": "now-7d/d"}}}
            ]
        }
    },
    aggs={
        "errors_per_day": {
            "date_histogram": {"field": "@timestamp", "calendar_interval": "day"}
        }
    },
    size=0
)
print(resp["aggregations"]["errors_per_day"]["buckets"])$escape$,
  $escape$python$escape$,
