INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '0e299221-54bb-4947-a424-e4c9a9bc3857',
  '00000000-0000-0000-0000-000000000001',
  $escape$Elasticsearch vs PostgreSQL JSONB — When GIN Indexes Beat Your Inverted Index$escape$,
  $escape$Elasticsearch's near-real-time search has a 1-second index refresh gap — writes aren't visible until the next refresh cycle. PostgreSQL with JSONB and GIN indexes eliminates that gap entirely with ACID-consistent full-text search.

A GIN (Generalized Inverted Index) on a JSONB column is Elasticsearch's inverted index equivalent, but inside a transaction. You get the same O(log n) term lookups via @@ full-text operators or @> containment queries, but reads always reflect the latest committed write — no refresh_interval tuning required.

Partition the table by created_at using range partitioning and PostgreSQL's partition pruning mirrors Elasticsearch's time-based index rollover strategy. Add pgvector's HNSW index on an embedding column alongside the GIN index, and a single SQL query handles both keyword and semantic search — no cross-cluster joins between Elasticsearch and a separate vector store.

The tradeoff is real: GIN indexes are slower to update than Elasticsearch's bulk segment merges. For write-heavy pipelines ingesting above 10k docs/sec, Elasticsearch's refresh model wins. Below that threshold, PostgreSQL's transactional consistency and zero operational overhead make it the sharper tool.$escape$,
  $escape$-- Replaces: PUT /logs-index with mappings + refresh_interval
CREATE TABLE logs (
  id        BIGSERIAL PRIMARY KEY,
  payload   JSONB NOT NULL,
  embedding vector(384),
  created_at TIMESTAMPTZ DEFAULT now()
) PARTITION BY RANGE (created_at);

CREATE INDEX idx_logs_gin  ON logs USING GIN  (payload);
CREATE INDEX idx_logs_hnsw ON logs USING hnsw (embedding vector_cosine_ops);

-- Replaces: GET /logs-index/_search { query: match, knn }
SELECT id, payload
FROM   logs
