INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '6ac79752-d602-40c4-884d-1310c9deb259',
  '00000000-0000-0000-0000-000000000001',
  $escape$Elasticsearch Snapshots — Nail Your RTO and RPO Without Guessing$escape$,
  $escape$Elasticsearch's snapshot API is your primary backup mechanism. Snapshots are incremental by default — only changed segments since the last snapshot are written, making frequent snapshots cheap. Register a repository first (S3, Azure Blob, GCS, or shared filesystem), then snapshot on a schedule using SLM (Snapshot Lifecycle Management).

RPO (Recovery Point Objective) maps directly to your SLM schedule frequency. A 1-hour schedule means you can lose up to 1 hour of data. RTO (Recovery Time Objective) depends on shard count, index size, and network throughput to your snapshot repo — test restores regularly; a 100GB index on S3 with 10 shards restores in minutes, not hours.

For point-in-time recovery, combine snapshots with index-level `_pit` (Point In Time) searches for read consistency, but actual data recovery still goes through snapshot restore. Use `indices.recovery.max_bytes_per_sec` to throttle restore throughput so production traffic isn't starved. Always restore into an alias — swap the alias post-restore so the cutover is instant and rollback is trivial.$escape$,
  $escape$# Register S3 snapshot repository
PUT /_snapshot/my_s3_repo
{
  "type": "s3",
  "settings": {
    "bucket": "my-es-backups",
    "region": "us-east-1"
  }
}

# SLM policy: snapshot every hour, retain 48 snapshots
PUT /_slm/policy/hourly-snapshots
{
  "schedule": "0 0 * * * ?",
  "name": "<hourly-snap-{now/d}>",
  "repository": "my_s3_repo",
  "config": { "indices": ["logs-*"], "include_global_state": false },
  "retention": { "count": 48 }
}

# Restore a specific snapshot to a renamed index
POST /_snapshot/my_s3_repo/hourly-snap-2026.04.15/_restore
{
  "indices": "logs-2026.04.15",
  "rename_pattern": "(.+)",
  "rename_replacement": "restored-$1"
}$escape$,
  $escape$bash$escape$,
