INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '609106a1-e688-428d-ba18-d219851d60ff',
  '00000000-0000-0000-0000-000000000001',
  $escape$Elasticsearch Security — Encryption, DLS/FLS, and Least-Privilege Roles$escape$,
  $escape$Elasticsearch's X-Pack security stack covers three layers you must harden before production. Transport encryption requires enabling TLS on both the HTTP layer (`xpack.security.http.ssl.enabled: true`) and the inter-node transport layer (`xpack.security.transport.ssl.enabled: true`) — skipping the transport layer leaves node gossip unencrypted even if your REST API is behind HTTPS. Encryption at rest isn't built into ES itself; you rely on OS-level encrypted volumes (dm-crypt/LUKS, Azure Disk Encryption) combined with the Elasticsearch keystore (`bin/elasticsearch-keystore`) to protect secrets like S3 repository credentials. For row-level access, ES uses Document-Level Security (DLS) and Field-Level Security (FLS) inside role definitions. DLS filters which documents a role can see via a query; FLS controls which fields are returned. Pair these with the principle of least privilege: create dedicated roles per service, never reuse the `elastic` superuser, and audit access with the `xpack.security.audit.enabled: true` flag. The `_security/role` API lets you define all of this programmatically.$escape$,
  $escape$PUT _security/role/logs_readonly
{
  "indices": [
    {
      "names": ["logs-*"],
      "privileges": ["read"],
      "query": "{\"term\": {\"tenant_id\": \"acme\"}}",
      "field_security": {
        "grant": ["@timestamp", "message", "log.level", "service.name"],
        "except": ["user.password", "payment.*"]
      }
    }
  ]
}$escape$,
  $escape$bash$escape$,
